// Validate input fields and sanitize platforms
const { post_text, image_url, platforms, post_type, schedule_at } = $json;

// Require post_text
if (!post_text || post_text.trim().length === 0) {
  throw new Error('post_text is required and cannot be empty');
}

// Default platforms if not provided
let targetPlatforms = platforms || ['instagram', 'linkedin', 'pinterest'];

// Ensure it's an array
if (typeof targetPlatforms === 'string') {
  targetPlatforms = targetPlatforms.split(',').map(p => p.trim().toLowerCase());
}

// ALWAYS remove facebook -- account is hacked
targetPlatforms = targetPlatforms.filter(p => p !== 'facebook' && p !== 'fb');

// Validate platforms against allowed list
const ALLOWED_PLATFORMS = ['instagram', 'tiktok', 'youtube', 'linkedin', 'pinterest'];
targetPlatforms = targetPlatforms.filter(p => ALLOWED_PLATFORMS.includes(p));

if (targetPlatforms.length === 0) {
  throw new Error('No valid platforms specified. Allowed: instagram, tiktok, youtube, linkedin, pinterest');
}

// Validate post_type if provided
const VALID_POST_TYPES = ['blog_share', 'review_highlight', 'seasonal_tip', 'before_after', 'test'];
const validatedPostType = post_type && VALID_POST_TYPES.includes(post_type) ? post_type : 'blog_share';

// Validate schedule_at if provided (must be ISO 8601)
let validatedSchedule = null;
if (schedule_at) {
  const parsed = new Date(schedule_at);
  if (isNaN(parsed.getTime())) {
    throw new Error('schedule_at must be a valid ISO 8601 datetime string');
  }
  if (parsed.getTime() < Date.now()) {
    throw new Error('schedule_at must be in the future');
  }
  validatedSchedule = parsed.toISOString();
}

return [{ json: {
  post_text: post_text.trim(),
  image_url: image_url || null,
  platforms: targetPlatforms,
  post_type: validatedPostType,
  schedule_at: validatedSchedule,
  platform_count: targetPlatforms.length
}}];

// Build the API payload for the auto-posting service
// Supports Upload-Post or LATE -- replace AUTOPOST_API_URL and AUTOPOST_API_KEY with real values
const { post_text, image_url, platforms, post_type, schedule_at, platform_count } = $json;

const timestamp = new Date().toISOString();

const payload = {
  text: post_text,
  platforms: platforms,
  metadata: {
    source: 'totalguard-n8n',
    post_type: post_type,
    created_at: timestamp,
    workflow: 'TG-AUTOPOST'
  }
};

// Add image if provided
if (image_url) {
  payload.media = [{
    type: 'image',
    url: image_url
  }];
}

// Add scheduling if provided
if (schedule_at) {
  payload.scheduled_at = schedule_at;
}

return [{ json: {
  api_url: 'AUTOPOST_API_URL',
  api_key: 'AUTOPOST_API_KEY',
  payload: payload,
  platform_count: platform_count
}}];

// Log the result and return a summary
const response = $json;
const inputData = $('Build API Payload').first().json;
const validatedData = $('Validate Input').first().json;

const statusCode = response.statusCode || response.status || 0;
const isSuccess = statusCode >= 200 && statusCode < 300;

const timestamp = new Date().toLocaleString('en-US', { timeZone: 'America/Chicago' });

const result = {
  success: isSuccess,
  status_code: statusCode,
  platforms: validatedData.platforms,
  platform_count: validatedData.platform_count,
  post_type: validatedData.post_type,
  post_text_preview: validatedData.post_text.substring(0, 80) + (validatedData.post_text.length > 80 ? '...' : ''),
  scheduled: validatedData.schedule_at ? true : false,
  schedule_at: validatedData.schedule_at || null,
  timestamp: timestamp,
  response_body: isSuccess ? (response.body || 'OK') : (response.body || 'Unknown error')
};

if (!isSuccess) {
  result.error = `Auto-post failed with status ${statusCode}. Response: ${JSON.stringify(response.body || {}).substring(0, 200)}`;
}

return [{ json: result }];
